import {BrowserRouter, Routes, Route} from "react-router-dom";
import Home from './Home.js'



function App() {
  return (
    <div className="container"> 
        <BrowserRouter>
          <Routes>
            <Route index element={<Home/>} />
            <Route path='/contact' element={<Contact />} />
            <Route path='/design' element={<Design />} />
          </Routes>
        </BrowserRouter>      
    </div>
  );
}

export default App;
